  END IF;

  IF scope_count <> 347 THEN
    RAISE EXCEPTION 'Pos-apply acm-neto: esperadas 347 rows com coverage_id/scope alvo, encontradas %', scope_count;
  END IF;

  IF total_count <> 347 THEN
    RAISE EXCEPTION 'Pos-apply acm-neto: total projetos_lei esperado 347, encontrado %', total_count;
  END IF;

  IF outside_target_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply acm-neto: % rows em projetos_lei ficaram fora do alvo aceito', outside_target_count;
  END IF;

  IF other_slugs_with_target <> 0 THEN
    RAISE EXCEPTION 'Pos-apply acm-neto: % rows de outros slugs com coverage_id alvo', other_slugs_with_target;
  END IF;

  IF lme_count_after <> 0 THEN
    RAISE EXCEPTION 'Pos-apply acm-neto: legislacao_mandato_executivo mudou de 0 para %', lme_count_after;
  END IF;

  RAISE NOTICE 'Pos-apply acm-neto Camara Lote A: projetos_lei=% coverage_scope=% legislacao_mandato_executivo=%', total_count, scope_count, lme_count_after;
END $$;
